import { useState } from "react";
import Header from "./Header";
import "./App.css";
import { Modal, TodoModal, AlertModal } from "./Modal";

export default function App() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [toggleAlert, setToggleAlert] = useState(false);
    const [todos, setTodos] = useState([]);

    const handleModal = function () {
        setIsModalOpen(!isModalOpen);
    };
    const handleAlert = function () {
        setToggleAlert(!toggleAlert);
    };

    return (
        <div className="App">
            <Header />
            <TodoBox handleModal={handleModal} todos={todos} />
            <Modal isModalOpen={isModalOpen} cl={"todo-modal"}>
                <TodoModal handleModal={handleModal} todos={todos} setTodos={setTodos} />
            </Modal>
            <Modal isModalOpen={toggleAlert} cl={"alert-modal"}>
                <AlertModal handleAlert={handleAlert} />
            </Modal>
        </div>
    );
}

const TodoBox = function ({ handleModal, todos }) {
    return (
        <>
            <div className="todo-box">
                <Card cl={"add-card"}>
                    <AddCard handleModal={handleModal} />
                </Card>
                {todos.map((todo) => {
                    return (
                        <Card cl={"todo-card"}>
                            <TodoCard todo={todo} />
                        </Card>
                    );
                })}
            </div>
        </>
    );
};
